namespace Payments;

/// <summary>
/// Abstraction over an external payment provider (Stripe, Braintree, etc.).
/// </summary>
public interface IPaymentProvider
{
    Task<ProviderChargeResponse> CreateChargeAsync(string cardToken, decimal amount);
    Task<ProviderRefundResponse> CreateRefundAsync(string chargeId);
}

public record ProviderChargeResponse(string ChargeId, bool Approved);
public record ProviderRefundResponse(string RefundId, bool Approved);

public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(cardToken);

        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");

        var response = await _provider.CreateChargeAsync(cardToken, amount);
        return new ChargeResult(response.ChargeId, response.Approved);
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(chargeId);

        var response = await _provider.CreateRefundAsync(chargeId);
        return new RefundResult(response.RefundId, response.Approved);
    }

    public WebhookResult ProcessWebhook(string eventType, string payload)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(eventType);
        ArgumentException.ThrowIfNullOrWhiteSpace(payload);

        return eventType switch
        {
            "charge.succeeded" => new WebhookResult(eventType, WebhookStatus.Processed),
            "charge.failed" => new WebhookResult(eventType, WebhookStatus.Processed),
            "refund.completed" => new WebhookResult(eventType, WebhookStatus.Processed),
            _ => new WebhookResult(eventType, WebhookStatus.Ignored),
        };
    }
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record WebhookResult(string EventType, WebhookStatus Status);

public enum WebhookStatus
{
    Processed,
    Ignored
}

