using Moq;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private Mock<IPaymentProvider> _providerMock = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _providerMock = new Mock<IPaymentProvider>(MockBehavior.Strict);
        _gateway = new PaymentGateway(_providerMock.Object);
    }

    // ──────────────────────────────────────────────
    //  Constructor
    // ──────────────────────────────────────────────

    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new PaymentGateway(null!));
    }

    // ──────────────────────────────────────────────
    //  ChargeAsync – happy paths
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessfulCharge()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_valid", 50.00m))
            .ReturnsAsync(new ProviderChargeResponse("ch_123", Approved: true));

        var result = await _gateway.ChargeAsync("tok_valid", 50.00m);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
        _providerMock.Verify(p => p.CreateChargeAsync("tok_valid", 50.00m), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderDeclinesCard_ReturnsUnsuccessfulCharge()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_declined", 100.00m))
            .ReturnsAsync(new ProviderChargeResponse("ch_456", Approved: false));

        var result = await _gateway.ChargeAsync("tok_declined", 100.00m);

        Assert.AreEqual("ch_456", result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallAmount_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_ok", 0.01m))
            .ReturnsAsync(new ProviderChargeResponse("ch_small", Approved: true));

        var result = await _gateway.ChargeAsync("tok_ok", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_ok", 999_999.99m))
            .ReturnsAsync(new ProviderChargeResponse("ch_large", Approved: true));

        var result = await _gateway.ChargeAsync("tok_ok", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_large", result.ChargeId);
    }

    // ──────────────────────────────────────────────
    //  ChargeAsync – validation / error paths
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_ok", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_ok", -5m));
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_ok", 10m))
            .ThrowsAsync(new InvalidOperationException("provider down"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_ok", 10m));
    }

    // ──────────────────────────────────────────────
    //  RefundAsync – happy paths
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessfulRefund()
    {
        _providerMock
            .Setup(p => p.CreateRefundAsync("ch_123"))
            .ReturnsAsync(new ProviderRefundResponse("re_789", Approved: true));

        var result = await _gateway.RefundAsync("ch_123");

        Assert.AreEqual("re_789", result.RefundId);
        Assert.IsTrue(result.Success);
        _providerMock.Verify(p => p.CreateRefundAsync("ch_123"), Times.Once);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderDeniesRefund_ReturnsUnsuccessful()
    {
        _providerMock
            .Setup(p => p.CreateRefundAsync("ch_old"))
            .ReturnsAsync(new ProviderRefundResponse("re_deny", Approved: false));

        var result = await _gateway.RefundAsync("ch_old");

        Assert.AreEqual("re_deny", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    // ──────────────────────────────────────────────
    //  RefundAsync – validation / error paths
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync("  "));
    }

    [TestMethod]
    public async Task RefundAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock
            .Setup(p => p.CreateRefundAsync("ch_bad"))
            .ThrowsAsync(new HttpRequestException("timeout"));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _gateway.RefundAsync("ch_bad"));
    }

    // ──────────────────────────────────────────────
    //  ProcessWebhook – known event types
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow("charge.succeeded")]
    [DataRow("charge.failed")]
    [DataRow("refund.completed")]
    public void ProcessWebhook_KnownEventType_ReturnsProcessed(string eventType)
    {
        var result = _gateway.ProcessWebhook(eventType, "{\"id\":\"evt_1\"}");

        Assert.AreEqual(eventType, result.EventType);
        Assert.AreEqual(WebhookStatus.Processed, result.Status);
    }

    // ──────────────────────────────────────────────
    //  ProcessWebhook – unknown event types
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow("customer.created")]
    [DataRow("invoice.paid")]
    [DataRow("unknown.event")]
    public void ProcessWebhook_UnknownEventType_ReturnsIgnored(string eventType)
    {
        var result = _gateway.ProcessWebhook(eventType, "{\"id\":\"evt_2\"}");

        Assert.AreEqual(eventType, result.EventType);
        Assert.AreEqual(WebhookStatus.Ignored, result.Status);
    }

    // ──────────────────────────────────────────────
    //  ProcessWebhook – validation
